72	static inline
73	Real ibeta_wrap(Real a, Real b, Real x)
74	{
75	    Real y;
76	
77	    if (std::isnan(a) || std::isnan(b) || std::isnan(x)) {
78	        return NAN;
79	    }
80	
81	    if ((a < 0) || (b < 0) || (x < 0) || (x > 1)) {
82	        sf_error("betainc", SF_ERROR_DOMAIN, NULL);
83	        return NAN;
84	    }
85	
86	    /* In limiting cases, SciPy treats `betainc` as a two parameter family
87	     * of functions of a single variable `x`, rather than as a function of
88	     * three variables `a`, `b`, `x`. The limit ``(a, b) -> (a0, b0)`` of
89	     * ``betainc(a, b, x)`` is treated as the pointwise limit in `x`.
90	     */
91	
92	    if (((a == 0) && (b == 0)) || (std::isinf(a) && std::isinf(b))) {
93	        /* In the limit (a, b) -> (0+, 0+), the Beta distribution converges
94	         * to a Bernoulli(p) distribution, where p depends on the path in
95	         * which (a, b) approaches (0+, 0+).
96	         * e.g. if a = t*b then the limiting distribution will be
97	         * Bernoulli(t / (t + 1)). The a = 0, b = 0 case is thus indeterminate.
98	         * A similar statement can be made for the limit (a, b) -> (inf, inf).
99	         */
100	        return NAN;
